   187  func shouldRemoveResourceAndSubresources(resourcesToRemove sets.String, resourceName string) bool {
   188          for _, resourceToRemove := range resourcesToRemove.List() {
   189                  if resourceName == resourceToRemove {
   190                          return true
   191                  }
   192                  // our API works on nesting, so you can have deployments, deployments/status, and deployments/scale.  Not all subresources
   193                  // serve the parent type, but if the parent type (deployments in this case), has been removed, it's subresources should be removed too.
   194                  if strings.HasPrefix(resourceName, resourceToRemove+"/") {
   195                          return true
   196                  }
   197          }
   198          return false
   199  }

